// Created: 2026-04-26 (M119 #1479)

/**
 * Session-scoped token accumulator state.
 *
 * Single source of truth for per-session token + cache tracking, shared by:
 *   - posttool/context-crossing-warn (writes estimatedTokens per tool result)
 *   - subagent-stop/unified-dispatcher (writes cacheRead/Creation tokens per agent end)
 *   - lifecycle/pre-compact-task-done-prompt (reads to gate on imminent zone +
 *     adapt message based on cache heat)
 *
 * Both writers do read-modify-write through atomicWriteSync. The two writers
 * fire on different lifecycle events (PostToolUse vs SubagentStop) so concurrent
 * write races are rare; when they do happen, last-writer-wins on the overlapping
 * fields. Token counts are incremental so worst case is one missed update —
 * acceptable for telemetry-grade data feeding heuristic thresholds.
 */

import { existsSync, readFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { atomicWriteSync } from './atomic-write.js';
import { getContextWindowTokens } from './context-window.js';
import type { ContentKind } from './token-estimator.js';

export interface AccumState {
  /** Estimated input tokens added by tool results this session. */
  estimatedTokens: number;
  /** Sum of cache_read_input_tokens across SubagentStop events this session. */
  cacheReadTokens: number;
  /** Sum of cache_creation_input_tokens across SubagentStop events this session. */
  cacheCreationTokens: number;
  /** Per-threshold one-shot fire flags ({"160000": true, ...}). */
  crossings: Record<string, boolean>;
  /** ISO timestamp of first state write — used to compute session age. */
  firstSeenAt: string;
  /** ISO timestamp of last state write. */
  updatedAt: string;
  lastToolName?: string;
  /** Counts per content kind (debug aid for #1478 estimator accuracy). */
  kindCounts?: Partial<Record<ContentKind, number>>;
  /** Image responses observed (model-side tokenization is separate). */
  imageResponses?: number;
}

export function getStateFile(projectDir: string, sessionId: string): string {
  return join(projectDir, '.claude', 'state', `session-${sessionId}-token-accum.json`);
}

function freshState(): AccumState {
  const now = new Date().toISOString();
  return {
    estimatedTokens: 0,
    cacheReadTokens: 0,
    cacheCreationTokens: 0,
    crossings: {},
    firstSeenAt: now,
    updatedAt: now,
    kindCounts: {},
    imageResponses: 0,
  };
}

export function loadAccumState(projectDir: string, sessionId: string): AccumState {
  const path = getStateFile(projectDir, sessionId);
  if (!existsSync(path)) return freshState();
  try {
    const parsed = JSON.parse(readFileSync(path, 'utf8')) as Partial<AccumState>;
    const fresh = freshState();
    return {
      estimatedTokens: Number(parsed.estimatedTokens) || 0,
      cacheReadTokens: Number(parsed.cacheReadTokens) || 0,
      cacheCreationTokens: Number(parsed.cacheCreationTokens) || 0,
      crossings:
        parsed.crossings && typeof parsed.crossings === 'object' ? parsed.crossings : {},
      firstSeenAt: parsed.firstSeenAt || fresh.firstSeenAt,
      updatedAt: parsed.updatedAt || fresh.updatedAt,
      lastToolName: parsed.lastToolName,
      kindCounts:
        parsed.kindCounts && typeof parsed.kindCounts === 'object' ? parsed.kindCounts : {},
      imageResponses: Number(parsed.imageResponses) || 0,
    };
  } catch {
    return freshState();
  }
}

export function saveAccumState(
  projectDir: string,
  sessionId: string,
  state: AccumState,
): void {
  const path = getStateFile(projectDir, sessionId);
  try {
    mkdirSync(dirname(path), { recursive: true });
    atomicWriteSync(path, JSON.stringify(state, null, 2));
  } catch {
    // best-effort — telemetry must never break the hook chain
  }
}

/** Cache hot threshold in cache-read tokens. Configurable via ORK_CACHE_HOT_THRESHOLD. */
export function getCacheHotThreshold(): number {
  const raw = process.env.ORK_CACHE_HOT_THRESHOLD;
  if (!raw) return 50_000;
  const parsed = parseInt(raw, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) return 50_000;
  return parsed;
}

/**
 * Decide whether the current session has accumulated enough cache value that
 * the user should prefer /compact (which preserves cache continuity) over
 * /clear (which nukes cache entirely).
 *
 * Returns:
 *   'hot'     — cache reads exceed threshold; recommend /compact
 *   'neutral' — cache reads modest OR session very short; current wording
 *
 * Opt out: ORK_NO_CACHE_AWARENESS=1 forces 'neutral'.
 */
export type CacheHeat = 'hot' | 'neutral';

const SHORT_SESSION_MS = 30 * 60 * 1000;

export function evaluateCacheHeat(state: AccumState): CacheHeat {
  if (process.env.ORK_NO_CACHE_AWARENESS === '1') return 'neutral';
  const ageMs =
    new Date(state.updatedAt).getTime() - new Date(state.firstSeenAt).getTime();
  if (Number.isFinite(ageMs) && ageMs < SHORT_SESSION_MS) return 'neutral';
  return state.cacheReadTokens >= getCacheHotThreshold() ? 'hot' : 'neutral';
}

/**
 * Load state for a session. Returns null when no real accumulator data exists
 * (fresh state with zero tokens + no crossings) — callers can treat null as
 * "no signal yet, don't gate on it".
 */
export function loadAccumStateOrNull(projectDir: string, sessionId: string): AccumState | null {
  try {
    const state = loadAccumState(projectDir, sessionId);
    if (state.estimatedTokens === 0 && Object.keys(state.crossings).length === 0) {
      return null;
    }
    return state;
  } catch {
    return null;
  }
}

const DEFAULT_IMMINENT_PCT = 0.85;

function readImminentPct(): number {
  const raw = process.env.ORK_CTX_IMMINENT_PCT;
  if (!raw) return DEFAULT_IMMINENT_PCT;
  const parsed = parseFloat(raw);
  if (!Number.isFinite(parsed) || parsed <= 0 || parsed >= 1) return DEFAULT_IMMINENT_PCT;
  return parsed;
}

/**
 * #1480 — true when the session has crossed the imminent zone threshold
 * (default 85% of `CLAUDE_MAX_CONTEXT`). Returns false for null/missing state.
 */
export function isInImminentZone(state: AccumState | null): boolean {
  if (!state) return false;
  const threshold = Math.round(getContextWindowTokens() * readImminentPct());
  return state.estimatedTokens >= threshold;
}
